import heapq
from collections import defaultdict

def agent_step(state, history):
    def heuristic(a, b):
        """Calculate Manhattan distance as heuristic."""
        return abs(a[0] - b[0]) + abs(a[1] - b[1])

    def a_star_search(start, goal, walls, blocks, search_depth_limit=10):
        """Perform A* search with depth limit for efficiency."""
        frontier = []
        heapq.heappush(frontier, (0, start))
        came_from = {}
        cost_so_far = {}
        came_from[start] = None
        cost_so_far[start] = 0
        depth = 0  # Track depth to limit search

        while frontier and depth < search_depth_limit:
            depth += 1  # Increment depth per iteration
            _, current = heapq.heappop(frontier)

            if current == goal:
                break

            for dx, dy in [(-3, 0), (3, 0), (0, -3), (0, 3)]:
                next_step = (current[0] + dx, current[1] + dy)
                if next_step in walls or next_step in blocks:
                    continue
                new_cost = cost_so_far[current] + 1
                if next_step not in cost_so_far or new_cost < cost_so_far[next_step]:
                    cost_so_far[next_step] = new_cost
                    priority = new_cost + heuristic(goal, next_step)
                    heapq.heappush(frontier, (priority, next_step))
                    came_from[next_step] = current

        if goal not in came_from:
            return None  # No path found
        current = goal
        path = []
        while current != start:
            path.append(current)
            current = came_from[current]
        path.reverse()
        return path

    def get_move_direction(from_pos, to_pos):
        """Get move direction based on positions."""
        if from_pos[0] < to_pos[0]:
            return "MOVE_RIGHT"
        elif from_pos[0] > to_pos[0]:
            return "MOVE_LEFT"
        elif from_pos[1] < to_pos[1]:
            return "MOVE_DOWN"
        elif from_pos[1] > to_pos[1]:
            return "MOVE_UP"
        return None

    def is_stuck(history):
        """Check if the agent is stuck based on history."""
        if len(history) >= 3 and not any(turn["moved"] for turn in history[-3:]):
            return True
        return False

    def get_direction_success_rates(history):
        """Calculate success rates for each direction from history."""
        direction_success = defaultdict(int)
        total_attempts = defaultdict(int)
        for turn in history:
            action = turn["action"].get("action")
            if action and action.startswith("MOVE_"):
                total_attempts[action] += 1
                if turn["moved"]:
                    direction_success[action] += 1
        success_rates = {}
        for direction in direction_success:
            if total_attempts[direction] > 0:
                success_rates[direction] = direction_success[direction] / total_attempts[direction]
            else:
                success_rates[direction] = 0
        return success_rates

    def update_dynamic_obstacles(history, player_pos):
        """Update obstacles based on history and heuristic hints."""
        dynamic_blocks = set()  # Start with heuristic hints
        if state["movement"].get("right_blocked", False):
            dynamic_blocks.add((player_pos[0] + 3, player_pos[1]))
        if state["movement"].get("left_blocked", False):
            dynamic_blocks.add((player_pos[0] - 3, player_pos[1]))
        if state["movement"].get("up_blocked", False):
            dynamic_blocks.add((player_pos[0], player_pos[1] - 3))
        if state["movement"].get("down_blocked", False):
            dynamic_blocks.add((player_pos[0], player_pos[1] + 3))

        # Learn from history: Add positions that caused failures
        for turn in history[-10:]:  # Look at recent history
            if not turn["moved"] and turn["action"].get("action").startswith("MOVE_"):
                failed_direction = turn["action"]["action"]
                failed_pos = player_pos  # Approximate; in reality, it's the position at that turn
                if failed_direction == "MOVE_RIGHT":
                    dynamic_blocks.add((failed_pos[0] + 3, failed_pos[1]))
                elif failed_direction == "MOVE_LEFT":
                    dynamic_blocks.add((failed_pos[0] - 3, failed_pos[1]))
                elif failed_direction == "MOVE_UP":
                    dynamic_blocks.add((failed_pos[0], failed_pos[1] - 3))
                elif failed_direction == "MOVE_DOWN":
                    dynamic_blocks.add((failed_pos[0], failed_pos[1] + 3))
        return dynamic_blocks

    player_pos = tuple(state["player"]["position"])
    goals = state["objects"]["goals"]
    walls = {tuple(wall["position"]) for wall in state["objects"]["walls"]}
    blocks = {tuple(block["position"]) for block in state["objects"]["blocks"]}

    dynamic_obstacles = update_dynamic_obstacles(history, player_pos)
    combined_blocks = blocks.union(dynamic_obstacles)  # Merge static and dynamic obstacles

    if is_stuck(history) or state["resources"]["steps_remaining"] < 10:
        # Enhanced piece switching: Select based on proximity and historical success
        selectables = state["objects"]["selectables"]
        if selectables and goals:
            goals_pos = [tuple(goal["position"]) for goal in goals]
            selectable_scores = {}
            for selectable in selectables:
                sel_pos = tuple(selectable["position"])
                if sel_pos != player_pos:
                    min_dist = min(heuristic(sel_pos, goal) for goal in goals_pos)
                    # Factor in historical success: Assume pieces closer with past successes are better
                    past_success = sum(1 for turn in history if turn["moved"] and tuple(turn["state"]["player"]["position"]) == sel_pos)
                    score = min_dist - past_success  # Lower score is better: prioritize closer with success
                    selectable_scores[sel_pos] = score
            if selectable_scores:
                best_sel = min(selectable_scores, key=selectable_scores.get)
                return {"action": "CLICK", "target_position": list(best_sel)}

    if goals:
        goal_pos = tuple(goals[0]["position"])  # Target the first goal
        path = a_star_search(player_pos, goal_pos, walls, combined_blocks)

        if path:
            next_step = path[0]
            move_direction = get_move_direction(player_pos, next_step)
            if move_direction:
                return {"action": move_direction}

        # Fallback: Use direction with highest success rate
        success_rates = get_direction_success_rates(history)
        if success_rates:
            best_direction = max(success_rates, key=success_rates.get)  # Highest success rate
            return {"action": best_direction}

    # Final fallback: Cycle through directions, skipping low-success ones
    cycle = ["MOVE_RIGHT", "MOVE_DOWN", "MOVE_LEFT", "MOVE_UP"]
    success_rates = get_direction_success_rates(history)
    available_cycle = [dir for dir in cycle if success_rates.get(dir, 0) > 0]  # Only directions with success
    if available_cycle:
        step = len(history) % len(available_cycle)
        return {"action": available_cycle[step]}
    else:
        return {"action": cycle[len(history) % len(cycle)]}  # Default cycle if none successful
